import React from 'react'
import './Footer.scss'
import pattern from '../../assets/images/pattern.png'


const Footer = (coctailInfo) => {
    return (
        <>
            <div className="footer">
                <div className="container footer__container">
                    <a className="footer__logo-link" href="/">
                        <span className="footer__logo">CoctailApp</span>
                    </a>
                    <img className="footer__pattern" src={pattern} alt="pattern"/>
                    <p className="footer__desc">2020. Тестовое приложение подбора коктелей по IBA</p>
                </div>

            </div>
        </>
    );
}

export default Footer;