import React from 'react'
import { Link } from 'react-router-dom'
import './Header.scss'
import Basket from '../Basket'


const Header = (props) => {
    return (
        <>
            <div className="header">
                <div className="header-top">
                    <div className="container header__container">
                        <Link className="header__logo" to='/'>CoctailApp</Link>
                        <span className="header__detail">SPA</span>
                        <nav>
                            <ul className="header__list">
                                <li className="header__item">
                                    <Link className="header__link" to='/categories/2'>Незабываемые</Link>
                                </li>
                                <li className="header__item">
                                    <Link className="header__link" to='/categories/1'>Современная классика</Link>
                                </li>
                                <li className="header__item">
                                    <Link className="header__link" to='/categories/3'>Напитки новой эры</Link>
                                </li>
                            </ul>
                        </nav>
                    </div>
                </div>
                <div className="header-bottom">
                    <div className="container header-bottom__container">
                        <Link className="header-bottom__link" to='/about'  >
                            <span className="header-bottom__about">О приложении</span>
                        </Link>
                        <Basket basket={props.basket} />
                    </div>
                </div>

            </div>

        </>
    );
};

export default Header;