import React from 'react'


const Ingridient = props => {
    const { bar, setAddToBarAction, item, addCoctailToAvialable } = props;

    const addBar = () => {
        console.log(item)
        if (!bar.some(elem => elem.id === item.id)) {
            setAddToBarAction(item)
        }

        setTimeout(addCoctailToAvialable, 500)
    }

    return (
        <li>
            <div className="my-bar__ingridient">
                <span>{item.name}</span>
                <button className="my-bar__add" data-name={item.name} onClick={addBar}>+</button>
            </div>
        </li>
    )
}


export default Ingridient