import React, { Component } from 'react'
import './FullCategory.scss'
import Coctail from '../../components/Coctail'


export default class FullCategory extends Component {

    render() {
        let matchingСocktails = []
        let nameCategory;

        for (let item of this.props.coctails) {
            if (item.categoryID === this.props.coctailCategory) {
                matchingСocktails.push(item)
                nameCategory = item.category
            }
        }

        let coctails = matchingСocktails.map((item) => {
            return (
                <Coctail coctailInfo={item} key={item.idDrink}/>
            )
        })


        return (
            <>
                <div className="full-category">
                    <div className="container">
                        <h2 className="full-category__title">{nameCategory}</h2>
                        <div className="full-category__blocks">
                            {coctails}
                        </div>
                    </div>
                </div>
            </>
        )
    }
}