import React from 'react'


const BasketItem = ({detailInfo}) =>{
    return (
        <div className="full-basket-good" key={detailInfo.id}>
            <div className="full-basket-good__wrap-img">
                <img className="full-basket-good__image" src={detailInfo.img} alt={detailInfo.name} />
            </div>
            <div className="full-basket-good__details">
                <span className="full-basket-good__name">{detailInfo.name}</span>
                <div className="full-basket-good__wrap">
                    <span className="full-basket-good__price">{detailInfo.price} <span>₽</span></span>
                    <span className="full-basket-good__count">Количество: 1</span>
                </div>
            </div>
        </div>
    )
}

export default BasketItem 