const initialState = []

export function ingridientsReducer(state = initialState, action) {
    switch (action.type) {
        case 'ADD_INGRIDIENT_TO_BAR':
            return [...state, action.payload]
        case "увеличить значение":
            return state.map(n => n.id === action.payload.id
                ? {
                    ...n,
                    count: Math.max(1, n.count + (({
                        increment: 1,
                        decrement: -1,
                    })[action.payload.action]) || 0),
                }
                : n
            );
        case 'REMOVE_INGRIDIENT_IN_BAR':
            return [...action.payload]
        default:
            return state
    }
}