import React, { Component } from 'react'
import './FullBasket.scss'
import BasketItem from '../BasketItem'

export default class FullBasket extends Component {

    generateList = () => {
        let detailInfo;
        return (this.props.basket.map(({ name }, i) => {
            detailInfo = this.getDetailInfo(name)
            return (
                <BasketItem detailInfo={detailInfo} key={i} />
            )
        }))
    }

    getDetailInfo = (item) => {
        let coc;
        this.props.ingridients.map((ingridient) => {
            if (ingridient.name === item) {
                coc = ingridient
            }
            return coc
        })
        return coc
    }


    render() {
        return (
            <div className="full-basket">
                <div className="container full-basket__container">
                    <h1 className="full-basket__title">Оформление заказа</h1>


                    {!this.props.basket.length && (
                        <p className="shelf-empty">
                            Добавьте товары в корзину <br />
                        </p>
                    )}

                    <div className="full-basket-all">
                        <span className="full-basket-all__title">Товары в корзине</span>

                        <div>
                            {this.generateList()}
                        </div>

                        <div className="full-basket-total">
                            <p className="full-basket-total__desc">Товаров на сумму: <span className="">{this.props.totalPrice}</span> ₽</p>
                        </div>
                    </div>

                </div>
            </div>
        )
    }
};