import React, { Component } from 'react'
import './Table.scss'

export default class Table extends Component {

    render() {

        let tableRows = this.props.data.map((item) => {
            return (
                <tr key={this.props.data.indexOf(item)}>
                    <td>{item.name}</td>
                    <td>{item.quantity}</td>
                    <td className="table__measure">{item.measure}</td>
                </tr>
            )
        })

        return (
            <>
                <table className='table'>
                    <thead>
                        <tr>
                            <th>Необходимые ингредиенты</th>
                            <th></th>
                            <th></th>
                        </tr>

                    </thead>
                    <tbody>
                        {tableRows}
                    </tbody>
                </table>
            </>
        )
    }
}


