import React, { Component } from 'react'
import './MyBar.scss'
import Bar from '../../components/Bar'
import Ingridients from '../../components/Ingridients'


export default class MyBar extends Component {

    render() {
        const { data, coctails, bar, setAddToBarAction, availableCoctails, removeIngridientInBarAction, setAddToBasketAction, setAddToAvialableCoctailsAction } = this.props
        
       /*  let clear;
        if (this.props.bar > 0) {
            return(clear = `<div className="my-bar__wrap-btn">
                <button className="my-bar__clean">Очистить бар</button>
                </div>`)
        } */

        return (
            <>
                <Ingridients
                    data={data}
                    bar={bar}
                    coctails={coctails}
                    availableCoctails={availableCoctails}
                    setAddToBarAction={setAddToBarAction}
                    setAddToAvialableCoctailsAction={setAddToAvialableCoctailsAction}
                />

                <div className="my-bar">
                    <div className="container my-bar__container">
                        <h2 className="my-bar__title">Мой бар</h2>
                        <div className="my-bar__blocks">
                            <Bar
                                data={this.props.data}
                                bar={this.props.bar}
                                basket={this.props.basket}
                                coctails={coctails}
                                setAddToBasketAction={setAddToBasketAction}
                                removeIngridientInBarAction={removeIngridientInBarAction}
                                setAddToAvialableCoctailsAction={setAddToAvialableCoctailsAction}
                            />
                        </div>
                    </div>
                </div>
            </>
        )
    }
}