import React, { Component } from 'react'
import { Link } from 'react-router-dom'
import './Coctail.scss'


export default class Coctail extends Component {

	render() {

		if (this.props.coctailInfo) {
			return (
				<div className="coctail" key={this.props.coctailInfo.idDrink}>
					<Link className="coctail__link" to={`/coctail/${this.props.coctailInfo.idDrink}`}>
						<div className="coctail__inner">
							<img className="coctail__image" src={this.props.coctailInfo.image} alt={this.props.coctailInfo.nameDrink} />
							<p className="coctail__name">{this.props.coctailInfo.nameDrink}</p>
						</div>
					</Link>

				</div>
			)
		}

		return (
			<>
				{/* <div className="coctail">
					<a className="coctail__link" href="/">
						<div className="coctail__inner">
							<img className="coctail__image" src="https://www.jamieoliver.com/drinks-tube/wp-content/uploads/2014/06/Margarita.jpg" alt="" />
							<p className="coctail__name">{this.props.coctailInfo.nameDrink}</p>
						</div>
					</a>
				</div> */}
			</>
		);
	}
}