import React from 'react'
import './BarItem.scss'


const BarItem = (barItem) => {
    const { name, price, basket, img, bar, coctails, removeIngridientInBarAction, setAddToBasketAction, setAddToAvialableCoctailsAction } = barItem;

    const addCoctailToAvialable = () => {
        let barItemsNames
        let suitableСocktail = []

        if (bar.length === 0) {
            barItemsNames = bar.name
        } else {
            barItemsNames = bar.map((item) => {
                return item.name
            })
        }

        coctails.map((coctail) => {
            //console.log(coctail.composition) //Состав коктейля
            for (let property in coctail.composition) {
                //console.log(coctail.composition[property].name)
                if (barItemsNames.includes(coctail.composition[property].name)) {
                    //console.log(coctail.idDrink)
                        suitableСocktail.push(coctail)
                }
            }
            return coctail
        })

        //console.log('suitableСocktail', suitableСocktail)

        var uniq = Array.from(new Set(suitableСocktail));
        //console.log('uniq', uniq)
        console.log('zzzzz', bar)
        setAddToAvialableCoctailsAction(uniq)
    }

    const removeFromBar = () => {
        let values = bar.filter(function (x) { return x.name !== barItem.name })
        removeIngridientInBarAction(values)

        addCoctailToAvialable()
    }

    const addBasket = () => {

        if (basket.length === 0) {
            setAddToBasketAction(barItem)
        } else {
            let contain = basket.some((element) => { return element.id === barItem.id })
            if (!contain) {
                setAddToBasketAction(barItem)
            }
        }
    }

    return (
        <div className="bar-item" data-name={name}>
            <div className="bar-item__inner">
                <div className="bar-item-front">
                    <img className="bar-item__img" src={img} alt={name} />
                    <p className="bar-item__name">{name}</p>
                </div>
                <div className="bar-item-back">
                    <button className="bar-item__remove" title="Удалить из бара" onClick={removeFromBar}>X</button>
                    <div className="bar-item__wrap-btn">
                        <button className="bar-item__btn" onClick={addBasket}>Добавить в корзину</button>
                    </div>
                    <span className="bar-item__price">Цена:</span>
                    <span className="bar-item__count">{price} руб.</span>
                </div>
            </div>
        </div>
    )
}


export default BarItem