import React, { Component } from 'react'
import './Bar.scss'
import BarItem from '../BarItem'


export default class Bar extends Component {

    generateBarItem = () => {
        const bar = this.props.bar;
        const { removeIngridientInBarAction, setAddToBasketAction, coctails, setAddToAvialableCoctailsAction  } = this.props
        const basket = this.props.basket

        if (bar.length > 0) {
            return (bar.map((item, i) => {
                return (
                    <BarItem
                        {...item}
                        bar={bar}
                        basket={basket}
                        coctails={coctails}
                        removeIngridientInBarAction={removeIngridientInBarAction}
                        setAddToBasketAction={setAddToBasketAction}
                        setAddToAvialableCoctailsAction={setAddToAvialableCoctailsAction}
                        key={i}
                    />
                )
            }))
        }
    }

    render() {

        return (
            <>
                {this.generateBarItem()}
            </>
        )
    }
}