import React, { Component } from 'react'
import { connect } from 'react-redux'
import { Route } from 'react-router-dom'
import './App.scss'
import About from '../About'
import FullBasket from '../FullBasket'
import Header from '../Header'
import Footer from '../Footer'

import MyBar from '../../containers/MyBar'
import AvailableCoctails from '../../containers/AvailableCoctails'
import FullCategory from '../../containers/FullCategory'
import CoctailDetail from '../CoctailDetail'

import { AddToBarAction } from '../../actions/addIngridientBarActions'
import { AddToBasketAction } from '../../actions/addBasketActions'
import { AddToAvialableCoctailsAction } from '../../actions/addToAvialableCoctails'
import { removeIngridientInBarAction } from '../../actions/removeIngridientInBar'


class App extends Component {
	render() {
		const { data, basket, bar, totalPrice, availableCoctails,
			setAddToBarAction,
			removeIngridientInBarAction,
			setAddToBasketAction,
			setAddToAvialableCoctailsAction
		} = this.props

		return (
			<>
				<div className="content">
					<Header basket={basket} />

					<Route exact path="/">
						<MyBar
							data={data.ingridients}
							bar={bar}
							basket={basket}
							coctails={this.props.data.drinks}
							availableCoctails={availableCoctails}
							setAddToBarAction={setAddToBarAction}
							removeIngridientInBarAction={removeIngridientInBarAction}
							setAddToBasketAction={setAddToBasketAction}
							setAddToAvialableCoctailsAction={setAddToAvialableCoctailsAction}
						/>
						<AvailableCoctails
							data={data.drinks}
							bar={bar}
							availableCoctails={availableCoctails}
						/>
					</Route>

					<Route exact path='/unforgettables' render={() => <FullCategory />} />

					<Route exact path='/about'>
						<About />
					</Route>

					<Route exact path='/full-basket'>
						<FullBasket
						totalPrice={totalPrice}
							basket={basket}
							ingridients={data.ingridients}
						/>
					</Route>

					<Route
						path='/categories/:id'
						render={({ match }) => {
							const { id } = match.params;
							return <FullCategory coctailCategory={id} coctails={this.props.data.drinks} />
						}} />

					<Route
						path='/coctail/:id'
						render={({ match }) => {
							const { id } = match.params;
							return <CoctailDetail coctailNumber={id} coctails={this.props.data.drinks} />
						}} />

				</div>
				<Footer />
			</>
		);
	}
}





const mapStateToProps = store => {
	return {
		data: store.data,
		bar: store.bar,
		basket: store.basket,
		availableCoctails: store.availableCoctails,
		totalPrice: store.basket.reduce((sum, p) => {sum += p.price * p.quantity;return sum;}, 0)
	}
}

const mapDispatchToProps = dispatch => {
	return {
		setAddToBarAction: ingridient => dispatch(AddToBarAction(ingridient)),
		removeIngridientInBarAction: ingridient => dispatch(removeIngridientInBarAction(ingridient)),
		setAddToBasketAction: goods => dispatch(AddToBasketAction(goods)),
		setAddToAvialableCoctailsAction: coctail => dispatch(AddToAvialableCoctailsAction(coctail)),
	}
}


export default connect(mapStateToProps, mapDispatchToProps)(App);